	.TITLE	INIWINCH	.PROC	M68000	.BASE	10.	MAJREV	= '3	MINREV	= '3; *************************************************************************; *									  *; *	          PROGRAMME D'INITIALISATION WINCHESTER			  *; *                                                                       *; *************************************************************************;   Initialise physiquement le winchester et met dans le bloc 3 les; donnes d'auto paramtrisation.			; FK 23.1.84	.REV	MAJREV-'0,MINREV-'0	.REF	SM8	.REF	BIOS	.REF	LIB	.REF	FOS	.REF	NTREL	.REF	GESMEM	.REF	DRIVERS	.REF	BIOSDRIV; Dclaration des compteurs d'addresse; ------------------------------------PCCODE		=	1PCVAR		=	2PCOFFSET	=	3.PC		PCCODE.LOC	0.PC		PCVAR.LOC	0; Dclarations Gnrale; ---------------------SM8		=	1		; Machine SM8SM100		=	2		;   <<	  SM100G150		=	3		;   <<    G150	NBWIN		=	4		; Nombre de winchestersWINMASQ		=	3		; Masque pour 4 winchestersWINECC		=	1		; Mode correction d'erreurNBTEST		=	50.		; Nb read pour recherche interleaveNBLKCYL		=	32.		; Nb block par cylindreLWINTYP		=	32.		; Longueur du champ typeLWINBLK		=	256.		; Longueur d'un secteurLWININTER	=	LWINBLK		; Longueur table d'interleaveLBUFFER		=	128.		; Longueur buffer gnralLBUBAD		=	6*100.		; Longueur buffer bad blockLBUCYL		=	(NBLKCYL+1)*LWINBLK ; Longueur buffer cylindreTERMIN		=	H'FFFF		; Terminateur de tableWIDENT		=	H'8080		; Identificateur bloc paramtresNBYTES		=	316		; Nb byte secteur ( miniscib ); Offset table paramtres winch; -----------------------------.PC	PCOFFSET.LOC	0WINPAR:OTCYL:	.BLK.16	1				; Nb cylindresOTSUR:	.BLK.16	1				; Nb surfaceOTSEC:	.BLK.16	1				; Nb secteursOTTYP:	.BLK.16	LWINTYP/2			; TypeOTPRE:	.BLK.16	1				; Start prcompOTRSTP:	.BLK.16	1				; Step rate restoreOTNSTP:	.BLK.16	1				; Step rate normalOTFLAG:	.BLK.8	1				; Flag BBADT	= 1					 ; In bad (sector/byte)	.EVENLWINPAR	=	.-WINPAR; Offset variables Winch; ----------------------.PC	PCVARWINVAR:OMACHINE:	.BLK.16	1		; Type machineOWINREL:	.BLK.32 NBWIN		; ^Non logique winch releaseOWININTER:	.BLK.16	LWININTER/2	; Table d'interleaveOBUCYL:		.BLK.16	LBUCYL/2	; Buffer data d'un cylindreOBUTEST:	.BLK.16	LBUCYL/2	; Buffer data teste interleaveOBUDATA:	.BLK.16	LWINBLK/2	; buffer dataOBUBAD:		.BLK.16	LBUBAD/2	; Buffer bad blocksOWINGRA:OBUFFER:	.BLK.16 LBUFFER/2	; Buffer usage gnralOWINNAME:	.BLK.32 1		; ^Nom physiqueOWINNBL:	.BLK.16	1		; Nb ligne de l'cranOADBASE:	.BLK.32	1		; Add de base du controleurOSEMINT:	.BLK.32	1		; Descripteur smaphore interruptOADVECT:	.BLK.32	1		; ^add vecteurOVECTINT:	.BLK.32	1		; Save vecteur interrupt driverOCHRONO:	.BLK.16 1		; Chonomtre de lectureOTIME:		.BLK.16	1		; Meilleur temps obtenuOWINSTAT0:	.BLK.8	1		; Status du programme BDRIVREL	= 	0		; No unit ou release fait (4 bits) BDRIVINS	=	7		; 1 = driver charg en mmoireOWINSTAT1:	.BLK.8	1		; Status du programme BDRIVCLO	=	0		; No unit ou close OK (4 bits) BGVAR		=	4		; Arbitrage appel GETVAR BNOKILL	=	5		; Indique si formatage destructifOWINFLAG:	.BLK.8	1		; Flag paramtresOWINUNIT:	.BLK.8	1		; No unit physiqueOABORT:		.BLK.8	1		; Syncro proc pre fils.EVEN; Bloc paramtres winchester (3); ------------------------------OWINPAR:OWINIDENT:	.BLK.16	1		; IdentificateurOWINCYL:	.BLK.16	1		; Nb cylindresOWINSUR:	.BLK.16	1		; Nb surfacesOWINSEC:	.BLK.16	1		; Nb secteursOWINBOOT:	.BLK.16	1		; Nb bloc pour le bootOWININTP:	.BLK.16	1		; Interleave piste ( pas utilis )OWININTS:	.BLK.16	1		; Interleave		.BLK.16	4		; Rserve ...OWINBLK:	.BLK.16	2		; Nb blocOWINTYP:	.BLK.16	LWINTYP/2	; Champ typeOWINPRE:	.BLK.16	1		; No cylindres start prcompOWINRSTP:	.BLK.16	1		; Step rate restoreOWINNSTP:	.BLK.16	1		; Step rate narmal		.BLK.16	4		; Rserve ...		.BLK.8	256-(.-OWINPAR).EVEN;.INS		INIWINCH0		; Insert.PC		PCVAROTGVAR:		.BLK.8	7*LGETCH	; Table paramtres pour GATVAR			       ^ Undefined symbolLTGVAR	=	.-OTGVAR		.BLK.16	1		; Terminateur de tableLWINVAR =	.-WINVAR.EVEN; Pripheriques du controleur; ---------------------------WBG150	=	H'8006B0+1		; Adresse de base controleur GESCOMP 150WBSM8	=	H'3B0+1			; Adresse de base controleur SMAKY 8WBSM100	=	H'FFFF8400		; Adresse de base controleur SMAKY 100                                	WINDATA	=	0.			; R&W: datasWINERRO	=	2.			; R  : registre d'erreurWINPRE	=	2.			; W  : adr de prcomp.WINSECC	=	4.			; R&W: compteur de secteurWINSEC	=	6.			; R&W: adresse du secteurWINCYLL	=	8.			; R&W: adr low  du cylindreWINCYLH	=	10.			; R&W: adr high du cylindreWINSDH	=	12.			; R&W: size / drive / headWINSTAT	=	14.			; R  : statutWINCOM	=	14.			; W  : commande; Pripherique du controleur floppy utilise par le winch; ------------------------------------------------------RDINQ		= H'3A4+1		; Status registerLDINQ		= RDINQ			; Commande registerWINCHINTEN 	= 5			; Enable/disable interruptADVSM8		= 27.*4			; Add vecteur winch SM8ADVG150		= 96.*4			; Add vecteur winch G150ADVSM100	= 28.*4			; Add vecteur winch SM100; Commande WD1001; ---------------COMRST	=	H'10			; Restore: dpl tte --> pist 0COMSEEK	=	H'70			; Seek: dpl tte qq.partCOMRSGL	=	H'20			; Read single blocCOM_DMA	=	0			; Mode non DMACOMWSGL	=	H'30			; Write single blocCOMFOR	=	H'50			; Format a track; Bit du reg de status; --------------------BWINBUSY	=	7		;  Opration en cours.BWINRDY		=	6		;  WD1000 prt pour commandeBWINWERR	=	5		;  Write fault on driveBWINSEEK	=	4		;  Seek termin sur le driveBWINDAR		=	3		;  Buffer prt (inutile)BWINERRO	=	0		;  Bit  1 dans reg d'erreur; Bit du registre d'erreur; ------------------------BWINBBD		=	7		;  Bad Block DetectBWINCRD		=	6		;  CRC Error - Data fieldBWINCRI		=	5		;  CRC Error - ID fieldBWINIDN		=	4		;  ID not foundBWINCAB		=	2		;  Command abortedBWINTR0		=	1		;  TR000 ErrorBWINDMA		=	0		;  DMA not found; Code programme; --------------.PC	PCCODESTART:INIWINCH:	LIB	?OPELIB	MOVE.32	#LWINVAR,D4	MOVE.16	#MTYPCP,D1	GESMEM	?GETMEM			; Requte mmoire param	JUMP,NE	ERSTOP1	MOVE.32	A4,A6	MOVE.32	#R16^PVAR,A1	MOVE.32	A4,{A1}				; Sauve ^variables	DEC.16	D410$:		CLR.8	{A4+}				; Init buffer	DECJ.16,NMO D4,10$	CALL	INIMACHINE			; Init paramtres fontion de machine	JUMP,NE	STOP1				; Machine connue ?	LIB	?GETDIM	SWAP.32	D4	SWAP.32	D3	AND.32	#H'FFFF,D4	DIV.16	D3,D4				; Nb ligne fentre   -> D4	MOVE.16	D4,{A6}+OWINNBL	LIB	?BUZZ	LIB	?AFTIM	.ASCII	/<EOP><CR><PCURS><VSPACE><2><NOROLL><TRUNC><NOEFLI>/	.ASCII	/INIWINCH  Rev <MAJREV>.<MINREV>/	.ASCIZ  /<CR>----------------------<CR><CR>/	.EVEN	LIB	?MAFTIM	.ASCII	/<'F><AFINV> ATTENTION CE PROGRAMME PEUT PROVOQUE LA DESTUCTION/	.ASCII	/ DES FICHIERS DU WINCHESTER <AFDIR><CR>/	.ASCIZ	/Entrez l'unit physique winchester : /	.ASCII	/<'E><AFINV> WARNING THIS PROGRAM CAN DESTROY ALL FILE IN TO/	.ASCII	/ WINCHESTER <AFDIR><CR>/	.ASCIZ	/Please enter the winchester unit : /	.8	0	.EVEN	MOVE.32	#R16^TUNIT,A3	LIB	?AFMENU50$:	LIB	?GETCAR			; Attend soft key unit phys	SUB.8	#F0,D3				; Test touche	JUMP,EQ	STOP1	MOVE.32	#R16^NAME0,A3			; ^Nom WIN_0 -> D3	MOVE.8	#0.,{A6}+OWINUNIT	COMP.8	#F3-F0,D3	JUMP,LS	60$				; $WIN_0 ?	MOVE.32	#R16^NAME1,A3	MOVE.8	#1,{A6}+OWINUNIT	COMP.8	#F6-F0,D3	JUMP,LS	60$				; $WIN_1 ?	MOVE.32	#R16^NAME2,A3	MOVE.8	#2,{A6}+OWINUNIT	COMP.8	#F9-F0,D3	JUMP,LS	60$				; $WIN_2 ?	MOVE.32	#R16^NAME3,A3	MOVE.8	#3,{A6}+OWINUNIT	COMP.8	#F12-F0,D3	JUMP,LS	60$				; $WIN_3 ?	LIB	?BUZZ	JUMP	50$60$:	MOVE.32	A3,{A6}+OWINNAME		; ^texte -> A3	LIB	?AFTEXT	LIB	?AFCR	CALL	OPENWIN				; Open exclusif	JUMP,NE	ERSTOP		CALL	RDPARAM	JUMP,EQ	RESTART1RESTART:	LIB	?MAFTIM	.ASCII  /<'F><EOP>Slection type winchester/	.ASCIZ  /<CR>--------------------------<CR><CR>/	.ASCII  /<'E><EOP>Select winchester type/	.ASCIZ	/<CR>-----------------------<CR><CR>/	.8	0	.EVEN	LIB	?MAFTIM	.ASCII	/<'F>Entrez le type de votre winchester /	.ASCIZ	/(Prec : paramtres prcdents) : <CR><CR>/	.ASCII	/<'E>Please enter the type of your winchester /	.ASCIZ	/(Prec : Preceding parameters) : <CR><CR>/	.8	0	.EVEN	CLR.16	D0	CLR.32	D1	MOVE.32	#R16^TWINPAR,A212$:	TEST.16	{A2}+A16^{D1}	JUMP,MI	14$				; Place vide dans table ?	MOVE.32	#{A2}+A16^{D1}+OTTYP,A3		; Affiche texte type	LIB	?AFTEXT	LIB	?AFTAB	LIB	?AFTAB	INC.16	D0	TEST.32	D0:#0	JUMP,NE	14$				; Return ?	CLR.16	D0	LIB	?AFCR14$:	ADD.32	#LWINPAR,D1			; Offset dans table winch  -> D1	COMP.32	#LTWINPAR,D1	JUMP,LO	12$	LIB	?AFCR	MOVE.32	#R16^TWIN,A3	LIB	?AFMENU20$:	LIB	?BUZZ			; Get type winch	LIB	?GETCAR	TEST.32	D3:#BCTKEY	JUMP,ZS	20$				; Touche fonction ?	COMP.8	#F0,D3	JUMP,EQ	STOP		COMP.8	#F0+SHIFT,D3	JUMP,EQ	20$				; Rserve	COMP.8	#F15,D3	JUMP,EQ	80$				; Type winch connu ?	COMP.8	#F15+SHIFT,D3	JUMP,EQ	20$				; Rserve	TCLR.32	D3:#BSHIFT			; Conv F1-F14 ,shift F1-F14	JUMP,ZS	30$				; ascii en nb 0-27	ADD.8	#14.,D3				; Add nb key inf si shift30$:		AND.16	#31.,D3		DEC.16	D3				; Nb 0-27    -> D3	MUL.16	#LWINPAR,D3			; Calcul ^paramtres	COMP.16	#LTWINPAR,D3			;	JUMP,HS	20$				; Offset > lg table param ?	MOVE.32	#R16^TWINPAR,A3	ADD.32	D3,A3				; ^paramtres -> A3	MOVE.16	#LWINBLK-1,D0	MOVE.32	#{A6}+OWINPAR,A1	MOVE.32	A3,A2	TEST.16	{A2}	JUMP,MI	20$				; Type vinch vide ?40$:	CLR.8	{A1+}				; Clear buffer paramtres	DECJ.16,NMO D0,40$	MOVE.32	#{A6}+OWINPAR,A1		; Transfert	MOVE.16	#WIDENT,{A1+}			; Identificateur	MOVE.16	{A2+},{A1+}			; Cylindre	MOVE.16	{A2+},{A1+}			; Surface	MOVE.16	{A2+},{A1+}			; Secteur	MOVE.8	{A3}+OTFLAG,{A6}+OWINFLAG	; Flag	MOVE.16	#16.,{A1+}			; Longueur boot	MOVE.16	#(LWINTYP+6)-1,D0		; Type,RSTP,NSTP,PRE	MOVE.32	#{A3}+OTTYP,A3	MOVE.32	#{A6}+OWINTYP,A150$:	MOVE.8	{A3+},{A1+}	DECJ.16,NMO D0,50$	80$:	CALL	CONFWINPAR			; Modif param winch	COMP.16	#ERKSTO,D7	JUMP,EQ	STOP				; Arrt ?RESTART1:	CALL	INSTALL				; Install driver	CALL	WINOPEN				; Open hardware	JUMP,NE	WINERRSELOP:	MOVE.32	#R16^TFOP,A3	LIB	?GETLAN			; Affiche menu	COMP.8	#'F,D3	JUMP,EQ	10$	MOVE.32	#R16^TEOP,A310$:	LIB	?AFMENU	LIB	?MAFTIM	.ASCII	/<'F><EOP>SELECTION OPERATION<CR>/	.ASCII	/-------------------<CR><CR>/	.ASCIZ	/Entrez votre choix : <CR>/	.ASCII	/<'E><EOP>TYPE WORK SELECTION<CR>/	.ASCII	/-------------------<CR><CR>/	.ASCIZ	/Please enter your choice : <CR>/	.8	0	.EVEN20$:	LIB	?BUZZ	LIB	?GETCAR	COMP.8	#'A-H'40,D3	JUMP,EQ	TESTRD				; ## Pour teste ##	SUB.8	#F0,D3	JUMP,EQ	STOP				; Stop          ?	COMP.8	#F3-F0,D3	JUMP,LS	OPCONV				; Convertion    ?	COMP.8	#F6-F0,D3	JUMP,LS	OPPART				; Mod partition ?	COMP.8	#F9-F0,D3	JUMP,LS	OPWRPAR				; Ecrit param   ?	COMP.8	#F12-F0,D3	JUMP,LS	OPFORMAT			; formate       ?	COMP.8	#F15-F0,D3	JUMP,LS	RESTART				; Select winch  ?	JUMP	20$OPOK:	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Winchester initialis correctement <CR>/	.ASCIZ	/<'E><CR>Winchester correctly inisialised <CR>/	.8	0	.EVENOPNOOK:	MOVE.16	#75,D4	NTREL	?DELMS	JUMP	SELOPOPCONV:		CALL	GPCONV				; Conv SIBEL -> PSOS		     ^ Undefined symbol	JUMP,PL	OPNOOK				; Erreur ?	CALL	WRPARAM				; Ecrit bloc 3	JUMP,NE	WINERR	JUMP	OPOKOPPART:	CALL	GESPAR		     ^ Undefined symbol	JUMP	SELOPOPWRPAR:	CALL	WRPARAM				; Ecrit bloc 3	JUMP,NE	WINERR	JUMP	OPOKOPFORMAT:	LIB	?MAFTIM	.ASCIZ	/<'F><EOP>Le winchester a t'il des blocs defectueux ? 		: / 	.ASCIZ	/<'E><EOP>Is it bad block in to winchester ? 			: /	.8	0	.EVEN	LIB	?YESNO	COMP.8	#ERKSTO,D7	JUMP,EQ	STOP	COMP.8	#ERKNO,D7	JUMP,EQ	10$	CALL	GETBAD				; Demande les bad block	JUMP	20$10$:	MOVE.16	#TERMIN,{A6}+OBUBAD		; Init fin table bad block20$:	TSET.8	{A6}+OWINSTAT1:#BNOKILL		; Set formattage no destructif	LIB	?MAFTIM	.ASCIZ	/<'F><CR><EOP>Formatage destructif ?   : /	.ASCIZ	/<'E><CR><EOP>Kill data in Formating ? :/	.8	0	.EVEN	LIB	?YESNO	JUMP,NE	30$	TCLR.8	{A6}+OWINSTAT1:#BNOKILL30$:	LIB	?MAFTIM	.ASCIZ	/<'F><CR><EOP><AFINV>Formate /	.ASCIZ	/<'E><CR><EOP><AFINV>Formating /	.8	0	.EVEN	MOVE.32	{A6}+OWINNAME,A3	LIB	?AFTEXT	LIB	?AFTIM	.ASCIZ	/ ? <AFDIR> : /	LIB	?YESNO	JUMP,NE	STOP	MOVE.32	#R16^TCLR,A3	LIB	?AFMENU			; Affiche menu	CALL	GETINTER			; Init rapp interleave	CALL	FORMAT				; Formate le winchester	JUMP,NE	WINERR	CALL	WRPARAM				; Ecrit bloc 3	JUMP,NE	WINERR	CALL	WRPART				; PSOS sur tout le disque	JUMP,NE	WINERR	JUMP	OPOK;---------------\;    FIN PROG	 >;---------------/;  Point de sortie du programme.;	IN	D7.16 : Erreur ventuelle;	OUT	-;	MOD	?WINERR:	COMP.16	#ERMFUNC,D7	JUMP,EQ	10$				; Panne du WD1001	COMP.16 #ERMDISK,D7	JUMP,NE	ERSTOP				; WD1001 absent ?	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Le contrleur n'est pas branch ou est en panne/	.ASCIZ	/<'E><CR>The WD1001 board is not connected or dead/	.8	0	.EVEN	JUMP	20$10$:	LIB	?MAFTIM	.ASCIZ	/<'F><EOP>Mauvais fonctionnement du controleur<CR>/	.ASCIZ	/<'E><EOP>Error with the WD1001 board<CR>/	.8	0	.EVEN	CALL	AFISTATUS			; Affiche status WD100120$:	LIB	?BUZZ	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Voulez vous faire un nouvel essai ? 			: /	.ASCIZ	/<'E><CR>Do you want try once more ? 				: /	.8	0	.EVEN	LIB	?YESNO	JUMP,EQ	SELOP	JUMP	STOPERSTOP:	CALL	CLOSEWIN			; Init winch pour ?AFERRORERSTOP1:	PUSH.16	D7	LIB	?AFCR	POP.16	D7	LIB	?AFERROR	LIB	?AFCR	LIB	?BUZZ 	MOVE.16	#2*50,D4	NTREL	?DELMS			; Pause de 2s	JUMP	STOP1STOP:		CALL	CLOSEWIN			; Ferme les OPENEXSTOP1:	MOVE.8	#EOP,D3	LIB	?AFCAR			; Efface la fentre	LIB	?CLOLIB	FOS	?STOP;	END	;---------------\;    AFISTATUS   >;---------------/;	Affiche l'etat des registre du WD1001 en cas; d'erreur;	IN	-;	OUT	-;	MOD	-AFISTATUS:	PUSHM.32 D2|D3|D4|D7|A3	CLR.32	D4	LIB	?AFTIM	.ASCII	/<CR>Status register WD1001/	.ASCIZ	/<CR>----------------------<CR>/	.EVEN	MOVE.8	#2**BAFDCM,D2			; Mode d'affichage -> D2	MOVE.8	#8,D3				; Nb de digits	   -> D3	LIB	?AFTIM	.ASCIZ	/<CR>Winchester   : /	.EVEN	MOVE.8	{A0}+WINSDH,D4	SR.8	#3,D4	AND.8	#3,D4	LIB	?AFDEC	LIB	?AFTIM	.ASCIZ	/<CR>Surface      : /	.EVEN	MOVE.8	{A0}+WINSDH,D4	AND.8	#7,D4	LIB	?AFDEC	LIB	?AFTIM	.ASCIZ	/<CR>Cylinder     : /	.EVEN	MOVE.8	{A0}+WINCYLH,D4	SL.16	#8,D4	MOVE.8	{A0}+WINCYLL,D4	LIB	?AFDEC	LIB	?AFTIM	.ASCIZ	/<CR>Sector       : /	.EVEN	CLR.16	D4	MOVE.8	{A0}+WINSEC,D4	LIB	?AFDEC	LIB	?AFTIM	.ASCIZ	/<CR><CR><AFINV>Status register<AFDIR><CR>/	.EVEN	MOVE.32	#R16^STATUS,A3	MOVE.8	{A0}+WINSTAT,D4	TSET.32	D4:#BWINERRO			; Set err bit clear	CALL	AFREG				; quand read reg err						; windone	LIB	?AFTIM	.ASCIZ	/<CR><AFINV>Error register <AFDIR><CR>/	.EVEN	MOVE.32	#R16^ERROR,A3	MOVE.8	{A0}+WINERRO,D4	CALL	AFREG	POPM.32	D2|D3|D4|D7|A3	RETAFREG:	MOVE.16	#7.,D210$:	TEST.32	D4:D2	JUMP,EQ	20$				; Bit 2^D2 set ?	LIB	?AFTEXT	LIB	?AFCR	JUMP	30$20$:		TEST.8	{A3+}				; Cherche le texte suivant	JUMP,NE	10$30$:	DECJ.16,NMO D2,10$			; Dcale le masque	RETSTATUS:		.ASCIZ	/Busy/	.ASCIZ	/Ready/	.ASCIZ	/Write fault/	.ASCIZ	/Seek complete/	.ASCIZ	/Data request/	.ASCIZ	/Data corrected/	.ASCIZ	/-/	.ASCIZ	/Error/	.EVENERROR:		.ASCIZ	/Bad block detected/	.ASCIZ	/Data uncorrectable/	.ASCIZ	/CRC error/	.ASCIZ	/ID not found/	.ASCIZ	/-/	.ASCIZ	/Aborded command/	.ASCIZ	/Track 0 error/	.ASCIZ	/DAM not found/	.EVEN;---------------\;   CONFWINPAR   >;---------------/;	Affiche les paramtres du winchester et demande; la confirmation de ceux-ci;	IN	-;	OUT	D7.16 : Etat aprs ?YESNO;	MOD	D7.16CONFWINPAR:	PUSHM.32 D2|D3|D4|A1|A2|A35$:	LIB	?MAFTIM	.ASCII  /<'F><EOP>Paramtres du winchester/	.ASCIZ  /<CR>-------------------------<CR>/	.ASCII  /<'E><EOP>Winchester parameters/	.ASCIZ	/<CR>----------------------<CR>/	.8	0	.EVEN	MOVE.32	#{A6}+OTGVAR,A1			; ^table param getvar -> A1	MOVE.32	A1,A2	MOVE.16	#LTGVAR-1,D2			; Init table10$:	CLR.8	{A2+}	DECJ.16,NMO D2,10$	MOVE.32	A1,A2	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Type du winchester   : /	.ASCIZ	/<'E><CR>Type of winchester   : /	.8	0	.EVEN	LIB	?GETCURS	MOVE.32	D3,{A2}+OGORGCH			; Coor org champ			      ^ Undefined symbol	MOVE.32	#{A6}+OWINTYP,A3	MOVE.32	A3,{A2}+OGVARCH			; ^variable			      ^ Undefined symbol	LIB	?AFTEXT	TSET.8	{A2}+OGSCH+1:#BTEXT		; Type champ			 ^ Undefined symbol	MOVE.16	#LWINTYP,{A2}+OGLGCH		; Lg champ				   ^ Undefined symbol	ADD.32	#LGETCH,A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Nombre de surfaces   : /	.ASCIZ	/<'E><CR>Number of surfaces   : /	.8	0	.EVEN	CLR.32	D4	MOVE.16	{A6}+OWINSUR,D4	MOVE.32	#{A6}+OWINSUR,A3	CALL	90$	ADD.32	#LGETCH,A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Nombre de cylindres  : /	.ASCIZ	/<'E><CR>Number of cylinders  : /	.8	0	.EVEN	MOVE.16	{A6}+OWINCYL,D4	MOVE.32	#{A6}+OWINCYL,A3	CALL	90$	ADD.32	#LGETCH,A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Nombre de secteurs   : /	.ASCIZ	/<'E><CR>Number of sectors    : /	.8	0	.EVEN	MOVE.16	{A6}+OWINSEC,D4	MOVE.32	#{A6}+OWINSEC,A3	CALL	90$	ADD.32	#LGETCH,A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Debut precomp 	     : /	.ASCIZ	/<'E><CR>Start precomp       : /	.8	0	.EVEN	MOVE.16	{A6}+OWINPRE,D4	MOVE.32	#{A6}+OWINPRE,A3	CALL	90$	MOVE.32	#{A6}+OWINCYL,A3	MOVE.32	A3,{A1}+OGMAXCH			; Dfinit val max			      ^ Undefined symbol	ADD.32	#LGETCH,A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Step rate de restore : /	.ASCIZ	/<'E><CR>Restore step rate    : /	.8	0	.EVEN	MOVE.16	{A6}+OWINRSTP,D4	MOVE.32	#{A6}+OWINRSTP,A3	CALL	95$	ADD.32	#LGETCH,A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Step rate normal     : /	.ASCIZ	/<'E><CR>Normal step rate     : /	.8	0	.EVEN	MOVE.16	{A6}+OWINNSTP,D4	MOVE.32	#{A6}+OWINNSTP,A3	CALL	95$		LIB	?AFCR	LIB	?AFCR	LIB	?GETCURS	LIB	?MAFTIM	.ASCIZ	/<'F>Acceptez-vous ces paramtres ? : /	.ASCIZ	/<'E>Do you accept this parameters ? : /	.8	0	.EVEN	LIB	?YESNO	COMP.16	#ERKNO,D7	JUMP,NE	20$		MOVE.32	#{A6}+OTGVAR,A1			; Pointeur table    : A1	CALL	GETVAR				; Ligne commentaire : D3		     ^ Undefined symbol	JUMP,EQ	5$15$:	CALL	RGETVAR		      ^ Undefined symbol	JUMP,EQ	5$				; Dplacement dpasse ?	LIB	?BUZZ	JUMP	15$	20$:	MOVE.16	{A6}+OWINSUR,D4			; Calcul nb blk	MUL.16	{A6}+OWINSEC,D4	MUL.16	{A6}+OWINCYL,D4	MOVE.32	D4,{A6}+OWINBLK	POPM.32	D2|D3|D4|A1|A2|A3	TEST.16	D7	RET90$:	MOVE.16	#2**BWORD+2**BGBCD,{A2}+OGSCH	; Type champ			^ Undefined symbol	LIB	?GETCURS	MOVE.32	D3,{A2}+OGORGCH			      ^ Undefined symbol	MOVE.16	#5,D3				; Nb digit a afficher -> D3	MOVE.8	#2**BAFDCM,D2			; Mode d'affichage    -> D2	LIB	?AFDEC	MOVE.32	A3,{A2}+OGVARCH			; ^variable			      ^ Undefined symbol	MOVE.16	D3,{A2}+OGLGCH			; Lg champ			     ^ Undefined symbol	RET95$:	MOVE.16	#2**BWORD+2**BIMMAX,{A2}+OGSCH	; Type champ			^ Undefined symbol	LIB	?GETCURS	MOVE.32	D3,{A2}+OGORGCH			      ^ Undefined symbol	CALL	AFSTP	MOVE.32	A3,{A2}+OGVARCH			; ^variable			      ^ Undefined symbol	MOVE.32	#R16^GETSTP,A3	MOVE.32	A3,{A2}+OGGETCH			; ^Rout get step rate			      ^ Undefined symbol	MOVE.16	#6,{A2}+OGLGCH			; Lg champ			     ^ Undefined symbol	MOVE.32	#7,{A2}+OGMAXCH			; Val max 			      ^ Undefined symbol	RET;---------------\;     AFSTP      >;---------------/;	Affiche le step rate;	IN	D4.16 : Step rate format WD1001;	OUT	-;	MOD	- AFSTP:	PUSHM.32 D2|D3|D4	AND.32	#H'FFFF,D4	MOVE.8	#4,D3				; Nb digit a afficher -> D3	MOVE.8	#2**BAFDCM,D2			; Mode d'affichage    -> D2	SR.16	#1,D4				; Affiche le step rate (ms)	JUMP,CC	10$	LIB	?AFDEC	LIB	?AFTIM	.ASCIZ	/.5 ms/	.EVEN	JUMP	20$10$:	LIB	?AFDEC	LIB	?AFTIM	.ASCIZ	/   ms/	.EVEN20$:	POPM.32	D2|D3|D4	RET;----------------\;     GETSTP      >;----------------/;	Attend le step rate;	IN	-;	OUT	D4.32 : Nb binaire;		EQ	Soft key 0 presse;	MOD	D4.32,D7.16GETSTP:	PUSHM.32 D0|D3|A3	LIB	?GETCURS	MOVE.32	D3,D0				; Pos curs -> D010$:	MOVE.32	#{A6}+OBUFFER,A3	MOVE.16	#LBUFFER,D3	LIB	?GETLINE	CLR.32	D3	CLR.32	D420$:	MOVE.8	{A3+},D3			; Test ligne	SUB.8	#CR,D3	JUMP,EQ	50$				; Fin ligne ?	COMP.8	#'.-CR,D3	JUMP,EQ	40$	SUB.8	#'0-CR,D3	COMP.8	#9.,D3	JUMP,HI	30$				; Chiffre correcte ?	MUL.16	#10.,D4				; Mise a jour de D4	ADD.32	D3,D4	JUMP	20$30$:	MOVE.32	D0,D3				; Erreur	LIB	?SETCURS	LIB	?BUZZ	LIB	?AFTIM			; Efface nb tapp	.ASCIZ	/<MSPACE><6>/	.EVEN	LIB	?SETCURS	JUMP	10$40$:	MOVE.8	{A3},D3	SUB.8	#CR,D3	JUMP,EQ 50$				; Fin de ligne ?	SUB.8	#'0-CR,D3	COMP.8	#9. ,D3	JUMP,HI	30$				; Chiffre correcte ?50$:	MUL.16	#10.,D4		ADD.32	D3,D4	DIV.16	#5,D4				; Format WD1001 -> D4	AND.16	#7,D4				; Step rate max : 3.5 ms	MOVE.32	D0,D3	LIB	?SETCURS	CALL	AFSTP				; Affi val normalise60$:		POPM.32 D0|D3|A3	RET;----------------\;     GETBAD      >;----------------/;	Demande la liste des bad block;	IN	A6.32 : ^buffer variables;	OUT	D7.16 : Erreur;	MOD	D7.16GETBAD:		PUSHM.32 D0..D6|A1..A5	GBREST:	TCLR.8	{A6}+OWINSTAT1:#BGVAR		; Init flag appel getvar	MOVE.32	#{A6}+OBUBAD+LBUBAD,A4	MOVE.16	#LBUBAD/2,D55$:		COMP.16	#TERMIN,{-A4}			; Supprime termin table	JUMP,EQ	7$	DEC.16	D5	JUMP,NE	5$7$:	CLR.16	{A4}	CLR.32	D5	MOVE.16	{A6}+OWINNBL,D5			; Nb ligne ecran     -> D5	SUB.32	#8.,D5	CLR.32	D0				; Compteur de bad blocs	MOVE.32	#{A6}+OBUBAD,A4			; ^table bad block10$:		MOVE.32	#{A6}+OTGVAR,A2			; ^table getvar      -> A2	LIB	?GETDIM	CLR.16	D3				; Hauteur d'un car   -> D3	MOVE.32	D3,D6	MOVE.32	A2,A1	MOVE.16	#LTGVAR-1,D320$:	CLR.8	{A1+}				; Init table paramtres 	DECJ.16,NMO D3,20$			; GETVAR	LIB	?MAFTIM	.ASCIZ	/<'F><EOP>Bloc numero <TAB>/	.ASCIZ  /<'E><EOP>Block number<TAB>/	.8	0	.EVEN	MOVE.32	A4,A3				; ^Bad surfaces      -> A3	CALL	DEFTBAD	CLR.32	D3	MOVE.16	{A6}+OWINSUR,D3	DEC.16	D3	MOVE.32	D3,{A2}+OGMAXCH			      ^ Undefined symbol	ADD.32	#LGETCH,A2			; ^Table par GETVAR  -> A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F>Tte<TAB><TAB>/	.ASCIZ  /<'E>Head<TAB><TAB>/	.8	0	.EVEN	ADD.32	#2,A3				; ^Bad cylindres     -> A3	CALL	DEFTBAD	CLR.32	D3	MOVE.16	{A6}+OWINCYL,D3	DEC.16	D3	MOVE.32	D3,{A2}+OGMAXCH			      ^ Undefined symbol	ADD.32	#LGETCH,A2			; ^Table par GETVAR  -> A2		      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F>Cylindre<TAB>/	.ASCIZ  /<'E>Cylinder<TAB>/	.8	0	.EVEN	ADD.32	#2,A3				; ^Bad secteurs     -> A3	CALL	DEFTBAD	CLR.32	D3	MOVE.16	{A6}+OWINSEC,D3	TEST.8	{A6}+OWINFLAG:#BBADT	JUMP,BS	25$				; Secteur ou byte  ?	DEC.16	D3	MOVE.32	D3,{A2}+OGMAXCH			      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F>Secteur<CR>/	.ASCIZ  /<'E>Sector <CR>/	.8	0	.EVEN	JUMP	27$25$:	MUL.16	#NBYTES,D3	DEC.16	D3	MOVE.32	D3,{A2}+OGMAXCH			      ^ Undefined symbol	LIB	?MAFTIM	.ASCIZ	/<'F>Octet<CR>/	.ASCIZ  /<'E>Byte <CR>/	.8	0	.EVEN27$:	MOVE.8	#'-,D330$:	LIB	?AFCAR	JUMP,EQ	30$	LIB	?AFCR	MOVE.32	D5,D1				; Nb ligne    -> D1	MOVE.32	D0,D6				; Bad bloc l1 -> D6	DEC.16	D1	MOVE.32	A4,A3				; ^variables  -> A3	MOVE.8	#5,D3				; Nb digits   -> D3	MOVE.8	#2**BAFDCM,D2			; Mode	      -> D240$:	MOVE.32	D6,D4				; No bad block	LIB	?AFDEC			LIB	?AFTAB		LIB	?AFTAB	MOVE.16	{A3+},D4			; Surface	LIB	?AFDEC			LIB	?AFTAB		LIB	?AFTAB	MOVE.16	{A3+},D4			; Cylindre 	LIB	?AFDEC			LIB	?AFTAB		LIB	?AFTAB	MOVE.16	{A3+},D4			; Secteur	LIB	?AFDEC	LIB	?AFCR	INC.16	D6	DECJ.16,NMO D1,40$	LIB	?AFCR	LIB	?GETCURS	MOVE.32	#{A6}+OTGVAR,A1			; ^table getvar      -> A1	TEST.8	{A6}+OWINSTAT1:#BGVAR	JUMP,BS	50$				; Getvar dja appel ?	CALL	GETVAR				; Entre bads blocks		     ^ Undefined symbol	JUMP,EQ	70$				; Fin ?	PUSH.16	SF	TSET.8	{A6}+OWINSTAT1:#BGVAR		; Signal getvar appel 1*	POP.16	F	JUMP,MI	60$				; Avant ou arrire ?	JUMP	55$50$:	CALL	RGETVAR0			; Entre bads blocks		       ^ Undefined symbol	JUMP,EQ	70$				; Fin ?	JUMP,MI	60$				; Avant ou arrire ?55$:	MOVE.32	D0,D3				; Avant	ADD.32	D5,D3	ADD.32	D5,D3	COMP.16	#(LBUBAD-2)/6,D3	JUMP,HI	10$				; Dpasse ?	MOVE.16	D5,D3				; Calcul org suivante	MUL.16	#6,D3	ADD.32	D3,A4				; Org		-> A4	ADD.32	D5,D0	JUMP 	10$60$:	MOVE.32	D0,D3				; Arrire	SUB.32	D5,D3		JUMP,MI	10$				; Dpasse ?	MOVE.16	D5,D3				; Calcul org Prcdente	MUL.16	#6,D3	SUB.32	D3,A4				; Org		-> A4	SUB.32	D5,D0	JUMP	10$70$:	MOVE.32	#{A6}+OBUBAD+LBUBAD,A3		; Fin table 	-> A3	MOVE.16	#(LBUBAD/6)-1,D080$:		MOVE.32	A3,A2	TEST.32	{-A3}	JUMP,NE	90$				; Fin table ?	TEST.16	{-A3}	JUMP,NE	90$				; Fin table ?	DECJ.16,NMO D0,80$	MOVE.32	A3,A290$:	MOVE.16	#TERMIN,{A2}			; Redfini fin de table	MOVE.32	A2,A4GBTRI:10$:	SUB.32	#6,A2				; Ordonne les bads blocks	MOVE.32	#{A6}+OBUBAD,A1	COMP.32	A1,A2	JUMP,LS 90$				; Fin ?20$:	MOVE.16	{A1}+6+2,D4	COMP.16	{A1}+2,D4			; Compare cyl	JUMP,EQ	50$			JUMP,HI 40$30$:	CALL	INV				; Invertion de 2 blocs40$:	ADD.32	#6,A1	COMP.32	A1,A2	JUMP,HI	20$				; Fin d'une passe ?	JUMP	10$50$:	MOVE.16	{A1}+6,D4	COMP.16	{A1},D4				; Compare surface	JUMP,LO	30$	JUMP,HI	40$	LIB	?BUZZ	LIB	?MAFTIM	.ASCII	/<'F><CR><AFINV>PLUS DE 1 SECTEUR DEFECTUEUX SUR LA MEME PISTE IMPOSSIBLE !<AFDIR>/	.ASCIZ	/<CR>Pressez une touche pour continuer /	.ASCII	/<'E><CR><AFINV>MORE 1 BAD SECTOR IN ONE TRACK IT IS UNPOSSIBLE !<AFDIR>/	.ASCIZ	/<CR>Press a key to continue /	.8	0	.EVEN	LIB	?GETCAR	JUMP	GBREST90$:		POPM.32	D0..D6|A1..A5	RETINV:	MOVE.32	{A1},D4	MOVE.32	{A1}+6,{A1}	MOVE.32 D4,{A1}+6	MOVE.16	{A1}+4,D4	MOVE.16	{A1}+6+4,{A1}+4	MOVE.16	D4,{A1}+4+6	RETDEFTBAD:					; Dfinit table pour getvar	MOVE.16	#2**BWORD+2**BGBCD+2**BIMMAX,{A2}+OGSCH			^ Undefined symbol	LIB	?GETCURS	ADD.32	D6,D3	ADD.32	D6,D3				; Additionne 2 lignes	MOVE.32	D3,{A2}+OGORGCH			; Origine champ			      ^ Undefined symbol	MOVE.32	A3,{A2}+OGVARCH			; ^variable			      ^ Undefined symbol	MOVE.16	D5,{A2}+OGNBCH			; Nombre de champ			     ^ Undefined symbol	MOVE.16	#6,{A2}+OGILDCH			; Increment de chargement			      ^ Undefined symbol	MOVE.16	#1,{A2}+OGIVCH			; Incrment vertical champ			     ^ Undefined symbol	MOVE.16	#6,{A2}+OGLGCH			; Lg champ			     ^ Undefined symbol	RET;----------------\;     OPENWIN     >;----------------/;	Assure que les winchs sont que sous le controle de; ce programme et verouille toute ouverture ultrieur, d'autre; part charge le driver winch si ce dernier n'est pas en RAM.;	IN	A6.16 : ^variables;	OUT	D7.16 : Erreur;	MOD	D7.16OPENWIN:	PUSHM.32 D2|D3|D4|A1|A2|A3|A4	MOVE.16 #50*3,D4	NTREL	?SETTIM			; Time out 1S	MOVE.16	#H'60+NBWIN-1,D2		; No winch  -> D210$:						; Test si winch utilis	BIOS	?DOPEXCL			; par un autre processus	JUMP,EQ	25$	COMP.16	#ERIDEV,D7		JUMP,EQ	30$				; Driver connu ?	COMP.16	#ERUUSE,D7	JUMP,EQ	20$				; Unit utilise ?	COMP.16	#ERTIMO,D7	JUMP,EQ	20$				; Driver ouvert ?	COMP.16	#ERALOP,D7	JUMP,NE	90$				; Ouvert multiple ?20$:	CALL	TRYREL				; Essaie close driver	JUMP,EQ	10$				; Nouvelle tentative open	JUMP	90$				; Release pas reussi !25$:	MOVE.16	D2,D1				; Set dans word status	AND.16	#WINMASQ,D1			; close nn OK	TSET.8	{A6}+OWINSTAT0:D1		; Poids fort de WINSTAT30$:	DEC.16	D2	COMP.16	#H'60,D2	JUMP,HS	10$				; Tous le drivers OK ?40$:	CLR.16	D790$:	MOVE.32 {A6}+OADVECT,A1	MOVE.32	{A1},{A6}+OVECTINT		; Sauve le vect du driver	MOVE.16	#-1,D4		PUSH.16	D7				; Save reg Erreur	NTREL	?SETTIM			; Set time out infini	POP.16	D7	POPM.32	D2|D3|D4|A1|A2|A3|A4	TEST.16	D7	RET;---------------\;  TRY RELEASE   >;---------------/;	Essaie de fermer un driver de winchester et met; a jour le byte de status du programme.;	IN	D2.16 : No phys du driver;		A6.16 : ^variables;	OUT	D7.16 : Erreur;	MOD	D7.16TRYREL:	PUSHM.32 D1|D2|D3|D4|A3|A4	MOVE.32	#R16^TLNAME,A3			; ^table nom logique -> A3	MOVE.16	D2,D1				; No phys -> D210$:	CLR.16	D3	FOS	?VASSIGN			; Cherche le nom phys	JUMP,NE	20$	EX.32	A3,A4				; ^nom phys -> A3	INC.32	A3	BIOS	?NAMDRIV			; No driver -> D2	JUMP,NE	20$	COMP.16	D1,D2		JUMP,EQ	40$				; Bon Nom logique ?20$:	EX.32	A3,A4				; ^nom log -> A330$:	TEST.8	{A3+}				; Cherche le prochain nom	JUMP,ZC	30$	COMP.16	#TERMIN,{A3}	JUMP,NE	10$				; Fin de la table ?	MOVE.16	#ERUUSE,D7			; Pas trouv	JUMP 50$40$:	EX.32	A3,A4				; ^Nom logique -> A3	FOS	?RELEASE	JUMP,NE	50$45$:	AND.16	#WINMASQ,D1	TSET.8	{A6}+OWINSTAT1:D1		; Signal WIN_X release		SL.8	#2,D1	MOVE.32	A3,{A6}+A16^{D1}+OWINREL	; Save ^nom log release50$:	POPM.32	D1|D2|D3|D4|A3|A4	TEST.16	D7	RETTLNAME:	.ASCIZ	/#MM0:/	.ASCIZ	/#MM1:/	.ASCIZ	/#MM2:/	.ASCIZ	/#MM3:/	.16	TERMIN	.EVEN;----------------\;    CLOSEWIN     >;----------------/;	Remet dans l'etat initial les drivers;	IN	A6.32 : ^variables;	OUT	-;	MOD	-CLOSEWIN:	PUSHM.32 D2|D3|D4|D7|A3	CALL	WINREL				; Release winch bas niveau	MOVE.16	#H'60,D2	CLR.16	D310$:	TCLR.8	{A6}+OWINSTAT0:D3	JUMP,EQ	15$	BIOS	?DCLOSE			; Ferme les drivers15$:	INC.16	D3	INC.16	D2	COMP.16	#H'60+NBWIN,D2	JUMP,LO	10$	TCLR.8	{A6}+OWINSTAT1:#BDRIVINS	; Dinstall driver	JUMP,EQ	20$				; Driver install ?	NTREL	?GTPNUM	EX.32	D3,D4				; No du process -> D3	MOVE.32	{A6}+OWINNAME,A3		; ^nom phys     -> A4	FOS	?DEINSTALL		20$:	MOVE.16	#NBWIN-1,D2			; Rinitialise les drivers30$:	TEST.8	{A6}+OWINSTAT1:D2	JUMP,EQ	40$	SL.16	#2,D2	MOVE.32	{A6}+A16^{D2}+OWINREL,A3	; Nom logique -> A3	FOS	?ENTER			; Reinitialise l'unit	RL.16	#2,D240$:	DECJ.16,NMO D2,30$	POPM.32	D2|D3|D4|D7|A3	RET;-----------------\;     INSTALL      >;-----------------/;	Installe le driver de l'unit a formater; ceci pour les test d'interleave.;	IN	-;	OUT	-;	MOD	FINSTALL:	PUSHM.32 D2|D3|D4|D7|A1|A2|A3|A4	MOVE.32	{A6}+OADVECT,A1	MOVE.32	{A6}+OVECTINT,{A1}		; Met le vecteur driver	NTREL	?GTPNUM	EX.32	D3,D4				; No du process -> D3	TEST.8	{A6}+OWINSTAT1:#BDRIVINS	; Dj un INSTALL fait ?	JUMP,EQ	20$10$:	MOVE.32	{A6}+OWINNAME,A3		; ^nom phys     -> A3	INC.32	A3				; Saute le $	BIOS	?NAMDRIV			; No drive      -> D2	BIOS	?DCLOSE	DEC.32	A3	FOS	?DEINSTALL20$:	MOVE.32	#{A6}+OWINIDENT+1,A2		; ^paramtres   -> A2	MOVE.32	#0,A3				; Pas de lien log <-> phys	MOVE.32	{A6}+OWINNAME,A4	FOS	?INSTALL			; Essaie d'installer driver	JUMP,EQ	40$				; Opration OK ?;	COMP.16	#ERNDEV,D7			; Driver dej install ?;	JUMP,EQ	10$30$:	TCLR.8	{A6}+OWINSTAT1:#BDRIVINS	JUMP	90$40$:	TSET.8	{A6}+OWINSTAT1:#BDRIVINS	MOVE.32	{A6}+OADVECT,A1	MOVE.32	{A1},{A6}+OVECTINT		; Save vecteur driver90$:	MOVE.32	#R16^WININT,A3			; Met vecteur programme	MOVE.32	{A6}+OADVECT,A1	MOVE.32	A3,{A1}	POPM.32 D2|D3|D4|D7|A1|A2|A3|A4	RET;-----------------\;     FORMAT	   >;-----------------/;	Formate physiquement le winch et en tenant compte des; bads blocks.;	IN	A6.32 : ^Variables;	OUT	D7.16 : Erreurs;	MOD	D7.16FORMAT:	PUSHM.32 D0|D1|D2|D3|D4|D5|A1	CALL	WINSEL				; Selectionne winch	JUMP,NE	90$	CALL	WINRST	JUMP,NE	90$				; Erreur ?	LIB	?MAFTIM	.ASCIZ	/<'F><EOP>Formate bloc : /	.ASCIZ	/<'E><EOP>Formating block : /	.8	0	.EVEN	LIB	?GETCURS		EX.32	D4,D3				; Pos curs -> D4	MOVE.16	{A6}+OWININTS,D3		; Raport Inter -> D3	CALL	GENINTER			; Gnre table interleave	CLR.32	D0				; D0 : compteur de blocs	CLR.32	D1	MOVE.16	{A6}+OWINSEC,D1			; Nb secteur -> D1	MOVE.32	#{A6}+OBUBAD,A1			; ^tabLe bad block -> A1	COMP.16	#TERMIN,{A1}	JUMP,NE	10$				; Pas de bad block ?	MOVE.32	#-1,D5				; Init plus de bad blocks	JUMP	20$10$:		MOVE.16	{A1}+2,D5			; Bad cyl   -> D5	MUL.16	{A6}+OWINSUR,D5			ADD.16	{A1},D5				; Bad piste -> D5	ADD.32	#4,A1				; ^bad secteur   -> A1	MUL.16	D1,D5				; Bad block modulo						; nb de secteurs -> D520$:	MOVE.32	D4,D3				; Affiche le no du bloc	LIB	?SETCURS			; sect 0 track courante	CLR.8	D2	MOVE.8	#8,D3	EX.32	D0,D4	LIB	?AFDEC	EX.32	D0,D4	COMP.32	D0,D5	JUMP,HI	40$				; Bad block sur cette piste	CLR.32	D3	MOVE.16	{A1+},D3			; Bad sector -> D3	TEST.8	{A6}+OWINFLAG:#BBADT	JUMP,BC	25$				; byte ou secteur ?	DIV.16	#NBYTES,D3			; Byte -> secteur25$:	CALL	PUTBAD				; Modifie interleave	INC.16	D1				; +1 secteurs a formater	CALL	WINFORT	JUMP,NE 90$				; Erreur d'ecriture	DEC.16	D1	MOVE.16	{A6}+OWININTS,D3		; Rapport inter -> D5	CALL	GENINTER			; Refait la table d'inter	COMP.16	#TERMIN,{A1}	JUMP,NE	30$				; Pas de bad block ?	MOVE.32	#-1,D5				; Init plus de bad blocks	JUMP	50$30$:		MOVE.16	{A1}+2,D5			; Bad cyl -> D5	MUL.16	{A6}+OWINSUR,D5			ADD.16	{A1},D5				; Bad piste -> D5	ADD.32	#4,A1				; ^bad secteur -> A1	MUL.16	D1,D5				; Bad block modulo	JUMP 	50$				; nb de secteurs -> D540$:		CALL	WINFORT				; Formate un piste	JUMP,NE	90$50$:	ADD.32	D1,D0	COMP.32	{A6}+OWINBLK,D0	JUMP,LO	20$				; Fin du formatage ?	CALL	WINRST	JUMP,NE	90$	CALL	WINUNSEL90$:	POPM.32	D0|D1|D2|D3|D4|D5|A1	TEST.16	D7	RET	;----------------\;    RDPARAM      >;----------------/;	Lit le bloc physique 3;	IN	A6.32 : ^variables;	OUT	D7.16 : Erreur;	MOD	D7.16RDPARAM:	PUSHM.32 D0|D1|A1	MOVE.32	#{A6}+OWINPAR,A1		; ^paramtres -> A1	MOVE.16	#300,{A6}+OWINCYL		; Init param par default	MOVE.16	#2,{A6}+OWINSUR	MOVE.16	#32,{A6}+OWINSEC	MOVE.16	#6,{A6}+OWINRSTP	MOVE.16	#6,{A6}+OWINNSTP	CALL	WINOPEN	JUMP,NE	90$	MOVE.32	#3,D0				; Bloc physique 3	CALL	WINSEL	JUMP,NE	90$	CALL	WINRD				; Lit le block	JUMP,NE	90$	CALL	WINUNSEL	COMP.16	#WIDENT,{A6}+OWINIDENT	JUMP,EQ	90$				; Bloc 3 Initialis ?	MOVE.16	#-1,D790$:	POPM.32	D0|D1|A1	TEST.16	D7	RET;----------------\;    WRPARAM      >;----------------/;	Ecrit le bloc physique 3;	IN	A6.32 : ^variables;	OUT	D7.16 : Erreur;	MOD	D7.16WRPARAM:	PUSHM.32 D0|D1|A1	CALL	WINSEL	JUMP,NE	90$	MOVE.32	#{A6}+OWINPAR,A1		; ^paramtres -> A1	MOVE.32	#3,D0				; Bloc physique 3	CALL	WINWR				; Ecrit le block	JUMP,NE	90$	CALL	WINUNSEL90$:	POPM.32	D0|D1|A1	TEST.16	D7	RET;----------------\;    WRPART       >;----------------/;	Ecrit le bloc physique 0 ( bloc dir partition };	IN	A6.32 : ^variables;	OUT	D7.16 : Erreur;	MOD	D7.16WRPART:	PUSHM.32 D0|A1|A2	MOVE.32	#{A6}+OBUDATA,A1		; ^buffer send -> A2	MOVE.16	#LWINBLK-1,D010$:	CLR.8	{A1+}	DECJ.16,NMO D0,10$	MOVE.32	#{A6}+OBUDATA,A2	MOVE.32	#R16^PSOS,A1	MOVE.16	#7.,D020$:	MOVE.8	{A1+},{A2+}	DECJ.16,NMO D0,20$	MOVE.32	#16.,{A2+}	MOVE.32	{A6}+OWINBLK,D0	SUB.32	#16.,D0	MOVE.32	D0,{A2+}	CLR.32	D0				; Bloc physique 0	MOVE.32	#{A6}+OBUDATA,A1	CALL	WINSEL	JUMP,NE	90$	CALL	WINWR				; Ecrit le block	JUMP,NE	90$	CALL	WINUNSEL90$:	POPM.32	D0|A1|A2	TEST.16	D7	RETPSOS:	.ASCIZ /PSOS    /	;       12345678	.EVEN;----------------\;    GETINTER	  >;----------------/;	Cherche l'interleave optimum et demende ; l'utilisateur de donner son choix.;	IN	A6.32 : ^variables;	OUT	-;	MOD	-GETINTER:	PUSHM.32 D0..A6	TEST.8	{A6}+OWINSTAT1:#BDRIVINS	JUMP,EQ	60$				; Driver trouv ?	LIB	?MAFTIM	.ASCIZ	/<'F><EOP>Recherche automatique du rapport d'interleave ? 	: /	.ASCIZ	/<'E><EOP>Automatic search interleave ? 			: /	.8	0	.EVEN	LIB	?YESNO	JUMP,NE	60$	MOVE.16	#-1,{A6}+OTIME			; Init temps min read	CLR.8	{A6}+OABORT	MOVE.32	#100,D5				; Lg SP     -> D5	MOVE.32	#R16^CHRONO,A5			; Add start -> A5;##	NTREL	?GETPRIO	MOVE.32	#4,D4				; Priorit  -> D4	MOVE.32	#R16^FILS,A3			; ^Nom	    -> A3	NTREL	?CRETASK		JUMP,NE	40$	MOVE.32	#1,D6				; Cpt rap interleave	MOVE.32	{A6}+OWINNAME,A3		; ^nom phys  -> A3	INC.32	A3				; Pas de $	BIOS	?NAMDRIV			; No driver  -> D2	JUMP,NE	40$	LIB	?MAFTIM	.ASCIZ	/<'F><EOP>Temps relatif :<CR>/	.ASCIZ	/<'E><EOP>Relative time :<CR>/	.8	0	.EVEN	MOVE.32	#{A6}+OWINGRA,A1		; ^Table point graph -> A110$:	MOVE.16	D6,D4				; Rap  -> D4	CALL	AFDEC				; Affi rap inter	LIB	?AFTIM	.ASCIZ	/ : /	.EVEN	MOVE.32	#R16^WININT,A4	MOVE.32	{A6}+OADVECT,A2	MOVE.32	A4,{A2}				; Vect programme	CALL	FORTEST				; Formate nb blocs	JUMP,NE	40$				; Erreur ?	MOVE.32	{A6}+OADVECT,A2	MOVE.32	{A6}+OVECTINT,{A2}		; Met vecteur driver	MOVE.32	#2**30,D4			; Absolu BLK 0  -> D4	MOVE.32	#{A6}+OBUTEST,A4		; ^destination  -> A4	MOVE.16	#TYPMM,D1			; Type driver   -> D1	CLR.16	{A6}+OCHRONO	MOVE.16	#NBTEST-1,D320$:	MOVE.32	#NBLKCYL,D5			; Nb BLK a lire -> D5	BIOS	?DREAD			; No driver     -> D2	JUMP,NE	40$25$:	DECJ.16,NMO D1,20$	MOVE.16	{A6}+OCHRONO,D4		MOVE.16	D4,{A1+}			; Save temps de lecture	CALL	AFDEC		LIB	?AFTIM	.ASCIZ	/   /				; Compare si le temps	.EVEN	COMP.16	{A6}+OTIME,D4			; de lecture est plus	JUMP,HI	30$				; petit que le prcdent	MOVE.16	D4,{A6}+OTIME	MOVE.16	D6,{A6}+OWININTS30$:	MOVE.32	D6,D4	DIV.16	#8,D4	AND.32	#H'FFFF0000,D4	JUMP,NE	35$				; Return ?	LIB	?AFCR35$:	INC.16	D6	COMP.16	{A6}+OWINSEC,D6	JUMP,LO	10$				; Tous les rap essays ?	JUMP	50$40$:	CLR.16	{A6}+OWININTS50$:	MOVE.32	#R16^WININT,A4	MOVE.32	{A6}+OADVECT,A2	MOVE.32	A4,{A2}				; Remet le vecteur prog	SET.8	{A6}+OABORT			; Stop fils	MOVE.16	#50*5,D4			; Time out 5s	NTREL	?SETTIM	NTREL	?WFABDESC	JUMP,EQ	55$				; Fils abord ?	LIB	?AFTIM	.ASCIZ	/<CR>Processus error<CR>/	.EVEN55$:	MOVE.16	#-1,D4				; Time out infini	NTREL	?SETTIM	CLR.32	D4	MOVE.16	{A6}+OWININTS,D4		; Rap inter -> D4	JUMP,EQ	60$				; Rap inter trouv ?	LIB	?AFCR	LIB	?MAFTIM	.ASCIZ	/<'F>Rapport d'interleave conseill 				: /	.ASCIZ	/<'E>Best interleave number found				: /	.8	0	.EVEN	CALL	AFDEC	LIB	?AFCR	MOVE.32	#{A6}+OWINGRA,A1		; ^Table point graph -> A1	LIB	?GETWDO	LIB	?GETCURS			; Org fentre        -> D3	SUB.32	D3,D4				; Din fentre	     -> D4	MOVE.16	{A6}+OWINSEC,D5	DEC.16	D5				; Nb point 	     -> D5	CALL	DGRAPH		     ^ Undefined symbol60$:	LIB	?MAFTIM	.ASCIZ	/<'F>Entrez le rapport d'interleave (dcimal) 		: /	.ASCIZ	/<'E>Please enter the interleave number (desimal)	: /	.8	0	.EVEN70$:	LIB	?GETCURS	EX.32	D3,D5	LIB	?BUZZ	LIB	?GETDEC	LIB	?AFCR	TEST.16	D4	JUMP,EQ	90$	COMP.16	{A6}+OWINSEC,D4	JUMP,HS	90$	MOVE.16	D4,{A6}+OWININTS	LIB	?AFCR	POPM.32	D0..A6	RET90$:	EX.32	D3,D5	LIB	?SETCURS	MOVE.8	#EFLI,D3	LIB	?AFCAR	JUMP	70$AFDEC:	PUSHM.32 D2|D3	AND.32	#H'FFFF,D4	MOVE.8	#2,D3	MOVE.8	#2**BAFDALL,D2	LIB	?AFDEC	POPM.32	D2|D3	RETCHRONO:	MOVE.16	#1,D410$:	NTREL	?DELMS	INC.16	{A6}+OCHRONO	TEST.8	{A6}+OABORT	JUMP,EQ	10$	NTREL	?ABORT;-----------------\;     FORTEST	   >;-----------------/;	Formate physiquement NBBLKTEST du winch et en tenant; compte des bads blocks.;	IN	D6.16 : Rap interleave;		A6.32 : ^Variables;	OUT	D7.16 : Erreurs;	MOD	D7.16FORTEST:	PUSHM.32 D0|D1|D3|D5|A1	CALL	WINSEL				; Selectionne winch	JUMP,NE	90$	CALL	WINRST	JUMP,NE	90$				; Erreur ?	MOVE.16	D6,D3	CALL	GENINTER			; Gnre table interleave	CLR.32	D0				; D0 : compteur de blocs	CLR.32	D1	MOVE.16	{A6}+OWINSEC,D1			; Nb secteur -> D1	MOVE.32	#{A6}+OBUBAD,A1			; ^tabLe bad block -> A1	COMP.16	#TERMIN,{A1}	JUMP,NE	10$				; Pas de bad block ?	MOVE.32	#-1,D5				; Init plus de bad blocks	JUMP	20$10$:		MOVE.16	{A1}+2,D5			; Bad cyl   -> D5	MUL.16	{A6}+OWINSUR,D5		ADD.16	{A1},D5				; Bad piste -> D5	ADD.32	#4,A1				; ^bad secteur   -> A1	MUL.16	D1,D5				; Bad block modulo						; nb de secteurs -> D520$:	COMP.32	D0,D5	JUMP,HI	40$				; Bad block sur cette piste	CLR.32	D3	MOVE.16	{A1+},D3			; Bad sector -> D3	TEST.8	{A6}+OWINFLAG:#BBADT	JUMP,BC	25$				; byte ou secteur ?	DIV.16	#NBYTES,D3			; Byte -> secteur25$:	CALL	PUTBAD				; Modifie interleave	INC.16	D1				; +1 secteurs a formater	CALL	WINFORT	JUMP,NE 90$				; Erreur d'ecriture	DEC.16	D1	MOVE.16	D6,D3				; Rapport inter -> D3	CALL	GENINTER			; Refait la table d'inter	COMP.16	#TERMIN,{A1}	JUMP,NE	30$				; Pas de bad block ?	MOVE.32	#-1,D5				; Init plus de bad blocks	JUMP	50$30$:		MOVE.16	{A1}+2,D5			; Bad cyl -> D5	MUL.16	{A6}+OWINSUR,D5			ADD.16	{A1},D5				; Bad piste -> D5	ADD.32	#4,A1				; ^bad secteur -> A1	MUL.16	D1,D5				; Bad block modulo	JUMP 	50$				; nb de secteurs -> D540$:		CALL	WINFORT				; Formate un piste	JUMP,NE	90$50$:	ADD.32	D1,D0	COMP.32	#NBLKCYL,D0	JUMP,LO	20$				; Fin du formatage ?	CALL	WINRST	JUMP,NE	90$	CALL	WINUNSEL90$:	POPM.32	D0|D1|D3|D5|A1	TEST.16	D7	RET		;-----------------\;    GENINTER      >;-----------------/;	Gnre la table d'interleave;	IN	D3.16 : Rapp interleave 1:D3.16;		A6.32 : ^variables;	OUT	-;	MOD	-GENINTER:	PUSHM.32 D0|D1|D2|D3|A1	MOVE.32	#{A6}+OWININTER,A1	MOVE.16	#(LWININTER/2)-1,D1		; Long buff -> D110$:		MOVE.16	#-1,{A1+}			; Init buffer	DECJ.16,NMO D1,10$	MOVE.32	#{A6}+OWININTER,A1	MOVE.16	{A6}+OWINSEC,D0			; Nb sec -> D0	SL.16	D0				; Long max table -> D0	SL.16	D3				; 2 bytes pour 1 block !	CLR.16	D1				; D1 cont blocs physiques	CLR.16	D2				; D2 cont blocs logiques20$:		TEST.8	{A1}+A16^{D1}		JUMP,MI	30$				; Pos deja remplie ?	ADD.16	#2,D1				; Block phys suivant -> D1	JUMP	40$30$:	MOVE.16	D2,{A1}+A16^{D1}			; Set bloc bon + no logique	INC.16	D2				; Nouv bloc logique -> D2	COMP.16	{A6}+OWINSEC,D2	JUMP,EQ 50$				; Table termine ?	ADD.16	D3,D1				; Nouv block phys * 2 -> D140$:	COMP.16	D0,D1	JUMP,LO	20$				; Dpassement nb sec phys ?	SUB.16	D0,D1	JUMP	20$50$:	MOVE.16	#TERMIN,{A1}+A16^{D0}		; Ferme la table	POPM.32	D0|D1|D2|D3|A1	RET;-----------------\;      PUTBAD      >;-----------------/;	Dclare dans la table d'interleave un bad block;	IN	D3.16 : No du secteur defectueux;		A6.32 : ^Variables;	OUT	-;	MOD	-PUTBAD:	PUSHM.32 A1|D1	CLR.32	D1	MOVE.16	{A6}+OWINSEC,D1	MOVE.32	#{A6}+OWININTER,A1	ADD.32	D1,A1	ADD.32	D1,A1				; ^Fin table -> A1	SUB.16	D3,D1				; Nb decalage -> D110$:	MOVE.16	{-A1},{A1}+2			; Dcale pour ins bad	DEC.16	D1	JUMP,NE	10$	MOVE.16	#H'80FF,{A1}			; Ins bad	POPM.32	D1|A1	RET;----------------\;## Test read ##  >;----------------/;;	IN	A6.32 : ^variables;	OUT	-;	MOD	-TESTRD:	PUSHM.32 D0|D3|D4|D7|A110$:	LIB	?MAFTIM	.ASCIZ	/<'F><EOP><AUTOCR>Entrez le bloc a lire ( END : fin )	: /	.ASCIZ	/<'E><EOP><AUTOCR>Enter the read block or END : /	.8	0	.EVEN	LIB	?GETDEC	COMP.8	#END,D3	JUMP,EQ	40$	LIB	?AFCR	EX.32	D4,D0	MOVE.32	#{A6}+OBUDATA,A1	CALL	WINSEL	JUMP,NE	30$	CALL	WINRD	JUMP,NE	30$	CALL	WINUNSEL	MOVE.16	#LWINBLK-1,D020$:	MOVE.8	{A1+},D3	LIB	?AFCODE	DECJ.16,NMO D0,20$	LIB	?AFCR	LIB	?AFCR	MOVE.32	#{A6}+OBUDATA,A1	MOVE.16	#LWINBLK-1,D025$:	MOVE.8	{A1+},D4	LIB	?AFX2	DECJ.16,NMO D0,25$	LIB	?AFCR	LIB	?AFCR	LIB	?GETCAR	JUMP	10$30$:		CALL	AFISTATUS	LIB	?GETCAR	JUMP	10$40$:	MOVE.8	#TRUNC,D3	LIB	?AFCAR	POPM.32	D0|D3|D4|D7|A1	JUMP	SELOP;--------------\;  INIMACHINE   >;--------------/;	 Initialise les paramtres variant d'une machine; a l'autre.;	IN	A6 : ^Variables;	OUT	A0 : ^Base du controleur;	MOD	A0INIMACHINE:	PUSH.32	D4	NTREL	?GETMACHINE	SWAP.32	D4	SR.32	#8,D4	COMP.8	#SM8,D4	JUMP,EQ	10$				; SM8   ?	COMP.8	#SM100,D4	JUMP,EQ	20$				; SM100 ?	COMP.8	#G150,D4	JUMP,EQ	30$				; G150  ?	LIB	?BUZZ	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Machine innconnue/	.ASCIZ	/<'E><CR>Unknow computer/	.8	0	.EVEN	POP.32	D4	CLRZ	RET10$:	MOVE.32	#WBSM8,A0			; ^base controleur	MOVE.32	#ADVSM8,{A6}+OADVECT		; ^add vecteur	MOVE.16	#SM8,{A6}+OMACHINE		; Type macine	JUMP	90$20$:	MOVE.32	#WBSM100,A0			; ^base controleur	MOVE.32	#ADVSM100,{A6}+OADVECT		; ^add vecteur	MOVE.16	#SM100,{A6}+OMACHINE		; Type macine	JUMP	90$30$:	MOVE.32	#WBG150,A0			; ^base controleur	MOVE.32	#ADVG150,{A6}+OADVECT		; ^add vecteur	MOVE.16	#G150,{A6}+OMACHINE		; Type macine;	JUMP	90$90$:	MOVE.32	A0,{A6}+OADBASE			; Sauve add base controleur	POP.32	D4	SETZ	RET;************************************************************************;*                     ROUTINES TRES BAS NIVEAU                         *;************************************************************************;---------------\;    WINOPEN     >;---------------/; Initialisation hard et soft du controleur; 	IN 	A6.32 : ^variables; 	OUT	D7.16 : Erreur; 	MOD	D7.16WINOPEN:	PUSHM.32 D4|A1|A4|A5	MOVE.8	#(((LWINBLK/256.)-1)&3)*2**5+WINECC*2**7,{A0}+WINSDH						; Dim bloc, ECC -> WD1001	COMP.8	#(((LWINBLK/256.)-1)&3)*2**5+WINECC*2**7,{A0}+WINSDH	JUMP,EQ 10$				; Controleur prsent  ?	MOVE.16	#ERMDISK,D7	JUMP	90$10$:		CLR.16	D4				; Init interrupt	NTREL	?CRESEM			; Cre smaphore interrupt	JUMP,NE	90$	MOVE.32	A5,{A6}+OSEMINT			; Save descript sem inter	MOVE.32	#R16^WININT,A4	MOVE.32	{A6}+OADVECT,A1	MOVE.32	A4,{A1}				; Add rout inter -> table						; vecteur interrupt	CALL	WINSEL				; Select winch	JUMP,NE	90$	CALL	WINRST				; Restore du winch	JUMP,NE	90$	CALL	WINUNSEL			; D-slectionne le drive90$:	POPM.32	D4|A1|A4|A5	TEST.16	D7	RET;--------------\;   WINREL	>;--------------/; Fermeture du winschester; 	IN	-; 	OUT	D7.16 : Erreur; 	MOD	D7.16WINREL:	PUSHM.32 A1|A5	CLR.16	D7	MOVE.32	{A6}+OSEMINT,A5	NTREL	?RACSEM	NTREL	?KILLSEM	NTREL	?RLASEM	CALL	WINUNSEL			; D-slectionne le drive	MOVE.32	{A6}+OADVECT,A1	MOVE.32	{A6}+OVECTINT,{A1}		; Remet le vect du driver	POPM.32	A1|A5	TEST.16	D7	RET;---------------\;      WINRD     >;---------------/; Lit un bloc sur le winchester; 	IN	D0.32 : No du bloc (256 bytes);		A1.32 : ^dest buffer;		A6.32 : ^variables;	OUT	D7.16 : Erreur; 	MOD	D7.16WINRD:	PUSHM.32 D1|A1	CALL	WINUPTSK			; Init coordonnes	MOVE.8	#COMRSGL,{A0}+WINCOM		; Commande read single BLK	CALL	WINDONE		JUMP,NE	90$	MOVE.16	#LWINBLK-1,D1			; puis transfre le bloc10$:	MOVE.8	{A0}+WINDATA,{A1+}	DECJ.16,NMO D1,10$90$:	POPM.32	D1|A1	TEST.16	D7	RET;---------------\;      WINWR     >;---------------/; Ecrit un bloc sur le winchester; 	IN	D0.32 : No du bloc (256 bytes);		A1.32 : ^org buffer;		A6.32 : ^variables;	OUT	D7.16 : Erreur; 	MOD	D7.16WINWR:	PUSHM.32 D1|A1	CALL	WINUPTSK			; Init coordonnes	MOVE.8	#COMWSGL,{A0}+WINCOM		; Commande write single BLK	MOVE.16	#LWINBLK-1,D1			; puis transfre le bloc10$:	MOVE.8	{A1+},{A0}+WINDATA	DECJ.16,NMO D1,10$	CALL	WINDONE	90$:	POPM.32	D1|A1	TEST.16	D7	RET;--------------\;   WINFORT	>;--------------/; 	Formate une track du winchester, le winch est; deja selectionn.; 	IN	D0.32 : No du premier block physique;		D1.16 : Nb de secteur a formater;		A6.32 : ^variables; 	OUT	D7.32 :	erreur;			ERMFUNC	Panne hardware;	MOD	D7.32WINFORT:	PUSHM.32 D0..D1|A1	TEST.8	{A6}+OWINSTAT1:#BNOKILL	JUMP,BC	30$				; Formattage destructif	?  oui	=> 30$	PUSHM.32 D0..D1				;*****   lecture cylindre  ****	MOVE.16	#NBLKCYL-1,D1			; Nb block par cyl -1		-> D1	MOVE.32	#{A6}+OBUCYL,A110$:	CALL	WINRD				; Lecture block	JUMP,EQ	20$				; Lcture OK		?  oui	=> 20$	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Erreur de lecture continue ?  : /	.ASCIZ	/<'E><CR>Read error continue ? : /	.8	0	.EVEN	LIB	?YESNO	JUMP,EQ	20$	MOVE.16	#ERMFUNC,D7	POPM.32	D0..D1	JUMP	90$20$:	ADD.A16	#LWINBLK,A1			; Nouvelle offset bloc		-> A1	INC.16	D0				; Passe au block suivant	DECJ.16,NMO D1,10$			; Tout les blocs lut	?  non	=> 10$	POPM.32	D0..D1				; ******************************30$:	CALL	WINUPTSK	MOVE.8	#COMFOR,{A0}+WINCOM		; Com formate	-> WD1001	MOVE.8	D1,{A0}+WINSECC			; Nb_sect 	-> WD1001	MOVE.32	#{A6}+OWININTER,A1		; ^table inter 	-> A1	MOVE.16	#(LWINBLK/2)-1,D140$:	MOVE.8	{A1+},{A0}+WINDATA		; Transfert byte tat sec	MOVE.8	{A1+},{A0}+WINDATA		; Transfert no bloc logique	DECJ.16,NMO D1,40$	CALL	WINDONE				; Attend fin formatage	JUMP,NE	90$	TEST.8	{A6}+OWINSTAT1:#BNOKILL	JUMP,BC	90$				; Formattage destructif	?  oui	=> 90$						;*****   ecriture cylindre  ****		MOVE.16	#NBLKCYL-1,D1			; Nb block par cyl -1		-> D1	MOVE.32	#{A6}+OBUCYL,A150$:	CALL	WINWR				; Ecrit block	JUMP,EQ	60$				; Ecriture OK		?  oui	=> 60$	LIB	?MAFTIM	.ASCIZ	/<'F><CR>Erreur d'ecriture essaie encore ?  : /	.ASCIZ	/<'E><CR>Write error try one time ? : /	.8	0	.EVEN	LIB	?YESNO	JUMP,EQ	50$60$:	ADD.A16	#LWINBLK,A1			; Nouvelle offset bloc		-> A1	INC.16	D0				; Passe au block suivant	DECJ.16,NMO D1,50$			; Tout les blocs Ecrit	?  non	=> 10$						; ******************************90$:	POPM.32	D0..D1|A1	TEST.16	D7	RET;---------------\;     WINRST     >;---------------/; Initialise le drive et place la tte en piste 0; 	IN	-; 	OUT	D7.32 : Erreur; 	MOD	D7.32WINRST:	PUSH.32	D0	MOVE.8	{A6}+OWINPRE+1,{A0}+WINPRE	; limite de prcompens.	CLR.32	D0	CALL	WINUPTSK			; Met les coordonnes	MOVE.8	#COMRST,D0			; 1 seul accs WD1001 !	OR.8	{A6}+OWINRSTP+1,D0		MOVE.8	D0,{A0}+WINCOM			; Restore  step lent	CALL	WINDONE				; Attend le positionnement	JUMP,NE 90$				; Erreur -> 90$	; Le ramped mode de RODIME ncessite un SEEK lent en zro suivi	; d'un ramped SEEK en zro pour s'initialiser correctement.	CLR.8	D0	CALL	WINUPTSK			; Init les coordonnes	MOVE.8	#COMSEEK,D0	OR.8	{A6}+OWINNSTP+1,D0		; Dplace en stp rapides	MOVE.8	D0,{A0}+WINCOM	CALL	WINDONE90$:	POPM.32	D0	TEST.16	D7	RET;---------------\;    WINUPTSK    >;---------------/; Calcule et initialise surface/piste/secteur; (drive dj initialis); 	IN	D0.32 : Numro du bloc  (ATTENTION: PAS DE TEST !!!); 	OUT	-; 	MOD	-WINUPTSK:	PUSH.32	D0	DIV.16	{A6}+OWINSEC,D0			; No_bloc / nb_sect -> D0	SWAP.32	D0	MOVE.8	D0,{A0}+WINSEC			; Reste = no_sector	CLR.16	D0				; Prpare D0.L pour DIV	SWAP.32	D0	DIV.16	{A6}+OWINSUR,D0			; Quotient / nb_surf -> DO	MOVE.8	D0,{A0}+WINCYLL			; No_cylindre low	SR.16	#8.,D0	MOVE.8	D0,{A0}+WINCYLH			; puis high	SWAP.32	D0				; Reste = no surface	AND.8	#H'F8,{A0}+WINSDH 		; Enlve head_sel precdent	OR.8	D0,{A0}+WINSDH			; met nouveau head_select	POP.32	D0	RET;--------------\;    WINSEL     >;--------------/;	 Slectionne un drive pour des oprations; suivantes.; 	IN	A6.32 : ^variables;	OUT	D7.16 :	Erreur;			ERIDEV	No de drive illgal;	MOD	D7.16WINSEL:	PUSH.8	D0	MOVE.8	{A6}+OWINUNIT,D0		; No winch -> DO	COMP.8	#NBWIN-1,D0	JUMP,HI 10$	SL.8	#3,D0				; No drive 2^3 -> D0	OR.8	#(((LWINBLK/256.)-1)&3)*2**5+WINECC*2**7,D0	MOVE.8	D0,{A0}+WINSDH			; No winch -> WD1001	POP.8	D0	CLR.16	D7	RET10$:	POP.8	D0	MOVE.16	#ERIDEV,D7	RET;---------------\;   WINUNSEL     >;---------------/; 	D-slectionne un drive pour des oprations; suivantes.; 	IN	-;	OUT	-; 	MOD	-WINUNSEL:	PUSHM.32 D0|D7	MOVE.8	#(((LWINBLK/256.)-1)&3)*(2**5)+WINECC*(2**7)+3*(2**3),D0	MOVE.8	D0,{A0}+WINSDH	; Met le ds le controlleur	POPM.32	D0|D7	RET;----------------\;     WINDONE     >;----------------/; Attend la fin du travail; 	IN	-	       |------ hight -----|------ low ------|; 	OUT	D7.32 : Erreur | Reg error WD1001 |  no err WD1001  |;	MOD	D7.32WINDONE:	PUSH.32 A5	COMP.16	#SM8,{A6}+OMACHINE	JUMP,NE	10$				; Smaky 8 ?	TSET.8	_VLDINQ:#WINCHINTEN		; Rafraichit miroire	TSET.8	LDINQ:#WINCHINTEN		; Autorise interrupt10$:	MOVE.32	{A6}+OSEMINT,A5	NTREL	?WAITEV			; Attend interrrupt20$:	TEST.8	{A0}+WINSTAT:#BWINBUSY		; Provisoire	JUMP,NE	20$		CLR.32	D7	TEST.8	{A0}+WINSTAT:#BWINERRO		; Test si erreur	JUMP,EQ	90$	MOVE.8	{A0}+WINERRO,D7			; Reg erreur -> D7	SWAP.32	D7	MOVE.16	#ERMFUNC,D7			; No erreur  -> D790$:	POP.32	A5	TEST.16	D7	RET;---------------\;     WININT	 >;---------------/;	Routine traitant l'interruption du winchester,; cette routine dbloque la subroutine WINDONE.;	IN	-;	OUT	-;	MOD	-WININT:	PUSHM.32 D0|D1|D7|A0|A1	MOVE.32	R16^PVAR,A1			; ^variables -> A1	MOVE.32	{A1}+OADBASE,A0			; Add base controleur -> A0	TEST.8	{A0}+WINSTAT:#BWINBUSY		; Clear INTRQ	COMP.16	#SM8,{A1}+OMACHINE	JUMP,NE	10$				; Smaky 8 ?	TCLR.8	_VLDINQ:#WINCHINTEN		; Met a jour miroire	TCLR.8	LDINQ:#WINCHINTEN		; Desable interrupt10$:	MOVE.32	{A1}+OSEMINT,A1	CALL	A16^_ISSIGNAL			; Call absolu.if	false	TEST.16	D7	JUMP,EQ	20$	.16	H'A042				; ?AFTIM Rom	.ASCIZ	/<CR>Fatal error _ISSIGNAL<CR>/	.EVEN	TRAP	#0				; Trap sur vect affi reg20$:.ENDIF	Ancien	POPM.32	D0|D1|D7|A0|A1	RETSF	; Texte unit physique; --------------------TUNIT:		.ASCIZ	//	.ASCIZ	/Stop/	;	|     |     |     |	.ASCIZ	//	.ASCIZ	/$WIN_0/	;	|     |     |     |	.ASCIZ	//	.ASCIZ	/$WIN_1/	;	|     |     |     |	.ASCIZ	//	.ASCIZ	/$WIN_2/	;	|     |     |     |	.ASCIZ	